    for _i in range(m + 1):
        cur.append(0)
    for i in range(1, n + 1):
        cur[0] = i
        for j in range(1, m + 1):
            var cost = 1
            if String(a[byte=i - 1]) == String(b[byte=j - 1]):
                cost = 0
            var d = prev[j] + 1
            var ins = cur[j - 1] + 1
            var sub = prev[j - 1] + cost
            var mn = d
            if ins < mn:
                mn = ins
            if sub < mn:
                mn = sub
            cur[j] = mn
        for j in range(m + 1):
            prev[j] = cur[j]
    return prev[m]

